def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    max_bin = np.max(bins) if len(bins) > 0 else 1
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        base_penalty = 0
        for power in range(2, 6):
            base_penalty += (ratio ** power) / (power * 3)
        adjusted_ratio = ratio * (capacity / max_bin)
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                penalty += ((ratio ** (2 * k + 1)) / (k * 3)) * (np.sin(k * np.pi / 4))
            priorities[i] = ratio ** 4 + penalty + base_penalty
            if capacity < item:
                priorities[i] += (item - capacity) ** 2 * 2
            if capacity % 2 == 0:
                priorities[i] *= 0.9
            else:
                priorities[i] *= 1.1
        elif 0 < ratio <= 1:
            score = 0
            sign = 1
            for j in range(1, 8):
                sign = -sign if j % 3 == 0 else sign
                term = sign * ((adjusted_ratio ** j) / (j ** 1.5))
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier + base_penalty
            if 0.7 < ratio < 0.95:
                extras = 0
                for m in range(1, 6):
                    extras += ((ratio ** m) * np.cos(m * np.pi / 3)) / (m + 2)
                priorities[i] += extras
            if capacity % 3 == 0 and item % 2 == 0:
                priorities[i] *= 0.85
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if capacity > 10 * item and item != 0:
            priorities[i] *= 0.5
        if priorities[i] == np.inf:
            continue
        if i % 2 == 0:
            for _ in range(3):
                priorities[i] += np.log1p(priorities[i] + 1) / 7
        else:
            priorities[i] *= np.exp(-ratio)
        if np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
